from typing import Any


class DataProcessor:
    def __init__(self, config: dict[str, Any]):
        """
        Initialize the DataProcessor with a configuration dict.

        Args:
            config: A dictionary containing:
                - 'required_fields': List of field names that must be present
                - 'transformations': Dict mapping field names to transformations
                  (can be a single transformation or list of transformations)
        """
        self.required_fields = config.get('required_fields', [])
        self.transformations = config.get('transformations', {})

    def validate(self, item: dict) -> bool:
        """
        Validate that an item has all required fields.

        Args:
            item: A dictionary representing a data item

        Returns:
            True if all required fields are present, False otherwise
        """
        for field in self.required_fields:
            if field not in item:
                return False
        return True

    def _apply_transformation(self, value: Any, transformation: str) -> Any:
        """
        Apply a single transformation to a value.

        Args:
            value: The value to transform
            transformation: The name of the transformation

        Returns:
            The transformed value
        """
        if transformation == 'uppercase':
            if isinstance(value, str):
                return value.upper()
            return value
        elif transformation == 'trim':
            if isinstance(value, str):
                return value.strip()
            return value
        elif transformation == 'to_int':
            try:
                return int(value)
            except (ValueError, TypeError):
                return value
        return value

    def transform(self, item: dict) -> dict:
        """
        Apply configured transformations to an item.

        Args:
            item: A dictionary representing a data item

        Returns:
            A new dictionary with the same keys, with values transformed
        """
        result = item.copy()

        for field, transforms in self.transformations.items():
            if field in result:
                value = result[field]
                if isinstance(transforms, list):
                    for transform in transforms:
                        value = self._apply_transformation(value, transform)
                else:
                    value = self._apply_transformation(value, transforms)
                result[field] = value

        return result

    def process(self, data: list[dict]) -> list[dict]:
        """
        Process a list of dictionaries by validating and transforming them.

        Args:
            data: A list of dictionaries to process

        Returns:
            A list of validated and transformed dictionaries
        """
        result = []

        for item in data:
            if self.validate(item):
                transformed_item = self.transform(item)
                result.append(transformed_item)

        return result
